191	    private var sectionSwitcher: some View {
192	        HStack(spacing: 6) {
193	            ForEach(MyListsSection.allCases) { section in
194	                sectionTabButton(section: section)
195	            }
196	        }
197	        .padding(6)
198	        .background(
199	            RoundedRectangle(cornerRadius: 12, style: .continuous)
200	                .fill(Color.primary.opacity(0.06))
