204	    private func sectionTabButton(section: MyListsSection) -> some View {
205	        let isSelected = selectedList == section.rawValue
206	        return Button {
207	            selectedList = section.rawValue
208	            focusedSection = section
209	        } label: {
210	            Label(section.title, systemImage: section.systemImage)
211	                .font(.subheadline)
212	                .fontWeight(isSelected ? .semibold : .regular)
213	                .foregroundStyle(isSelected ? .white : .primary)
214	                .frame(maxWidth: .infinity)
215	                .padding(.vertical, 7)
216	                .padding(.horizontal, 12)
217	                .background(
218	                    RoundedRectangle(cornerRadius: 8, style: .continuous)
219	                        .fill(isSelected ? Color.accentColor : Color.clear)
220	                )
221	                .overlay(
222	                    RoundedRectangle(cornerRadius: 8, style: .continuous)
223	                        .stroke(focusedSection == section ? Color.accentColor : .clear,
224	                                lineWidth: 2)
225	                )
226	        }
227	        .buttonStyle(.plain)
228	        .focusable()
229	        .focused($focusedSection, equals: section)
230	        .focusEffectDisabled()
231	        .accessibilityIdentifier("myLists.section.\(section.title)")
232	        // Tab from any section tab moves focus into the movies / lists
233	        // below; arrow keys still navigate between the three tabs.
234	        .onKeyPress(.tab, phases: .down) { press in
235	            guard !press.modifiers.contains(.shift) else { return .ignored }
236	            focusedSection = nil
237	            isListFocused = true
238	            return .handled
239	        }
240	        .onKeyPress(.rightArrow) { moveSection(offset: 1) }
241	        .onKeyPress(.leftArrow) { moveSection(offset: -1) }
242	    }
243	
244	    private func moveSection(offset: Int) -> KeyPress.Result {
245	        let all = MyListsSection.allCases
246	        guard let current = focusedSection,
247	              let idx = all.firstIndex(of: current) else {
248	            return .ignored
249	        }
250	        let nextIdx = idx + offset
251	        guard all.indices.contains(nextIdx) else { return .ignored }
252	        let next = all[nextIdx]
253	        focusedSection = next
254	        selectedList = next.rawValue
255	        return .handled
256	    }
