258	    private enum MyListsSection: Int, CaseIterable, Identifiable, Hashable {
259	        case wishlist, seenlist, customLists
260	        var id: Int { rawValue }
261	        var title: String {
262	            switch self {
263	            case .wishlist: return "Wishlist"
264	            case .seenlist: return "Seenlist"
265	            case .customLists: return "Custom Lists"
266	            }
267	        }
268	        var systemImage: String {
269	            switch self {
270	            case .wishlist: return "heart.fill"
271	            case .seenlist: return "eye.fill"
272	            case .customLists: return "pin.fill"
273	            }
274	        }
