277	    private func macOSListView(props: Props) -> some View {
278	        VStack(spacing: 0) {
279	            sectionSwitcher
280	                .padding(.horizontal, 16)
281	                .padding(.top, 12)
282	                .padding(.bottom, 10)
283	
284	            ScrollViewReader { scrollProxy in
285	                ScrollView {
286	                    // Eager VStack rather than LazyVStack: on macOS a
287	                    // LazyVStack's lazily-created rows don't acquire an
288	                    // accessibility identity even once they're laid out
289	                    // on-screen, so list rows become unreachable by VoiceOver
290	                    // and unqueryable in UI tests. My Lists holds user-curated
291	                    // collections (dozens of items, not thousands), so eager
292	                    // rendering costs little and restores row accessibility.
293	                    VStack(alignment: .leading, spacing: 0) {
294	                        currentSectionContent(props: props)
295	                    }
296	                    .padding(.horizontal, 4)
297	                    .padding(.bottom, 24)
298	                }
299	                .focusable()
300	                .focused($isListFocused)
301	                .focusEffectDisabled()
302	                .onKeyPress(.downArrow) {
303	                    let ids = currentSectionItemIds(props: props)
304	                    return moveHighlight(ids: ids, forward: true, scrollProxy: scrollProxy)
305	                }
306	                .onKeyPress(.upArrow) {
307	                    let ids = currentSectionItemIds(props: props)
308	                    return moveHighlight(ids: ids, forward: false, scrollProxy: scrollProxy)
309	                }
310	                .onKeyPress(.return) { openHighlighted(props: props) }
311	                .onKeyPress(characters: .init(charactersIn: " ")) { _ in openHighlighted(props: props) }
312	                // Shift+Tab (delivered as the back-tab character U+0019 on macOS)
313	                // moves focus back to the currently selected section tab.
314	                .onKeyPress(characters: CharacterSet(charactersIn: "\u{19}"), phases: .down) { _ in
315	                    isListFocused = false
316	                    focusedSection = MyListsSection(rawValue: selectedList) ?? .wishlist
317	                    return .handled
318	                }
319	            }
320	        }
321	        .onChange(of: selectedList) { _, _ in
322	            // When the user switches section, reset the highlight to the
323	            // first item of the new list.
324	            highlightedItemId = currentSectionItemIds(props: props).first
325	        }
326	        .navigationDestination(item: $selectedMovie) { nav in
327	            MovieDetail(movieId: nav.id)
328	                .macBackKeyboardShortcut()
329	        }
330	        .navigationDestination(item: $selectedCustomList) { nav in
331	            CustomListDetail(listId: nav.id)
332	                .macBackKeyboardShortcut()
333	        }
334	        .toolbar {
335	            ToolbarItem(placement: .automatic) {
336	                Menu {
337	                    sortMenuButtons { self.selectedMoviesSort = $0 }
338	                } label: {
339	                    Image(systemName: "line.horizontal.3.decrease.circle")
340	                        .resizable()
341	                        .frame(width: 22, height: 22)
342	                }
343	                .accessibilityLabel("Sort")
344	                .accessibilityIdentifier("myLists.sortButton")
345	            }
346	        }
347	    }
