350	    private func currentSectionContent(props: Props) -> some View {
351	        switch MyListsSection(rawValue: selectedList) ?? .wishlist {
352	        case .wishlist:
353	            moviesRows(movieIds: props.wishlist,
354	                       props: props,
355	                       emptyText: "No movies in your wishlist yet",
356	                       sectionHeader: "\(props.wishlist.count) movies in wishlist (\(selectedMoviesSort.title()))")
357	        case .seenlist:
358	            moviesRows(movieIds: props.seenlist,
359	                       props: props,
360	                       emptyText: "No movies in your seenlist yet",
361	                       sectionHeader: "\(props.seenlist.count) movies in seenlist (\(selectedMoviesSort.title()))")
362	        case .customLists:
363	            customListsRows(props: props)
364	        }
365	    }
