367	    @ViewBuilder
368	    private func moviesRows(movieIds: [Int],
369	                            props: Props,
370	                            emptyText: String,
371	                            sectionHeader: String) -> some View {
372	        Text(sectionHeader)
373	            .font(.subheadline)
374	            .foregroundStyle(.secondary)
375	            .padding(.horizontal, 12)
376	            .padding(.bottom, 6)
377	
378	        if movieIds.isEmpty {
379	            Text(emptyText)
380	                .foregroundStyle(.secondary)
381	                .frame(maxWidth: .infinity)
382	                .padding(.vertical, 40)
383	        } else {
384	            ForEach(Array(movieIds.enumerated()), id: \.offset) { _, id in
385	                MovieRow(movieId: id, displayListImage: false)
386	                    .frame(maxWidth: .infinity, alignment: .leading)
387	                    .padding(.horizontal, 8)
388	                    .padding(.vertical, 6)
389	                    .contentShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
390	                    .macFocusHighlight(isFocused: highlightedItemId == id)
391	                    .id(id)
392	                    .onTapGesture {
393	                        highlightedItemId = id
394	                        isListFocused = true
395	                    }
396	                    .onTapGesture(count: 2) {
397	                        selectedMovie = MovieNav(id: id)
398	                    }
399	                    .accessibilityIdentifier("myLists.movie.\(id)")
400	            }
401	        }
402	    }
403	
404	    @ViewBuilder
405	    private func customListsRows(props: Props) -> some View {
406	        Button {
407	            isEditingFormPresented = true
408	        } label: {
409	            HStack(spacing: 12) {
410	                Image(systemName: "plus.circle.fill")
411	                    .font(.title2)
412	                    .foregroundStyle(Color.steam_blue)
413	                Text("Create custom list")
414	                    .foregroundStyle(Color.steam_blue)
415	                    .font(.body)
416	                Spacer()
417	            }
418	            .padding(.horizontal, 10)
419	            .padding(.vertical, 10)
420	            .contentShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
421	        }
422	        .buttonStyle(.plain)
423	        .accessibilityIdentifier("myLists.createCustomListButton")
424	
425	        if props.customLists.isEmpty {
426	            Text("No custom lists yet. Create one to group movies however you like.")
427	                .foregroundStyle(.secondary)
428	                .frame(maxWidth: .infinity)
429	                .padding(.vertical, 40)
430	        } else {
431	            ForEach(props.customLists) { list in
432	                CustomListRow(list: list,
433	                              coverMovie: CustomListPresentation.coverMovie(for: list,
434	                                                                           movies: props.movieLookup))
435	                    .macFocusHighlight(isFocused: highlightedItemId == list.id)
436	                    .id(list.id)
437	                    .onTapGesture {
438	                        highlightedItemId = list.id
439	                        isListFocused = true
440	                    }
441	                    .onTapGesture(count: 2) {
442	                        selectedCustomList = CustomListNav(id: list.id)
443	                    }
444	                    // The row is driven by `.onTapGesture` (single = highlight,
445	                    // double = open), not a Button, so on macOS its accessibility
446	                    // gets merged away and isn't queryable. Replace the row's
447	                    // accessibility with a real Button so it surfaces as a stable,
448	                    // labelled element (findable as `myLists.customList.<id>` in
449	                    // UI tests) while keeping the gesture-based visual behaviour.
450	                    // VoiceOver activation intentionally navigates straight to the
451	                    // detail (no highlight step), matching the sighted double-tap.
452	                    .accessibilityRepresentation {
453	                        Button(list.name) {
454	                            selectedCustomList = CustomListNav(id: list.id)
455	                        }
456	                        .accessibilityIdentifier("myLists.customList.\(list.id)")
457	                    }
458	            }
459	        }
460	    }
461	
462	    private func currentSectionItemIds(props: Props) -> [Int] {
463	        switch MyListsSection(rawValue: selectedList) ?? .wishlist {
464	        case .wishlist:    return props.wishlist
465	        case .seenlist:    return props.seenlist
466	        case .customLists: return props.customLists.map { $0.id }
467	        }
468	    }
469	
470	    private func moveHighlight(ids: [Int],
471	                               forward: Bool,
472	                               scrollProxy: ScrollViewProxy) -> KeyPress.Result {
473	        guard !ids.isEmpty else { return .ignored }
474	        if let current = highlightedItemId,
475	           let idx = ids.firstIndex(of: current) {
476	            let nextIdx = idx + (forward ? 1 : -1)
477	            if ids.indices.contains(nextIdx) {
478	                let next = ids[nextIdx]
479	                highlightedItemId = next
480	                withAnimation { scrollProxy.scrollTo(next, anchor: .center) }
481	            }
482	        } else {
483	            let first = ids.first
484	            highlightedItemId = first
485	            if let first { withAnimation { scrollProxy.scrollTo(first, anchor: .center) } }
486	        }
487	        return .handled
488	    }
489	
490	    private func openHighlighted(props: Props) -> KeyPress.Result {
491	        guard let id = highlightedItemId else { return .ignored }
492	        let section = MyListsSection(rawValue: selectedList) ?? .wishlist
493	        switch section {
494	        case .customLists:
495	            selectedCustomList = CustomListNav(id: id)
496	        case .wishlist, .seenlist:
497	            selectedMovie = MovieNav(id: id)
498	        }
499	        return .handled
500	    }
501	    #endif
502	
503	    @ViewBuilder
504	    private func screen(props: Props) -> some View {
505	        if showNavigationTitle {
506	            listView(props: props).navigationTitle("My Lists")
507	        } else {
508	            listView(props: props)
509	        }
510	    }
511	
512	    func body(props: Props) -> some View {
513	        Group {
514	            if embedInNavigationStack {
515	                NavigationStack {
516	                    screen(props: props)
517	                }
518	            } else {
519	                screen(props: props)
520	            }
521	        }
522	        .sheet(isPresented: $isEditingFormPresented) {
523	                CustomListForm(editingListId: nil).environmentObject(self.store)
524	        }
525	    }
526	}
